function changeSubscription(userId, currentPlan, newPlan) {
    // Validate userId
    if (!userId || typeof userId !== 'string' || userId.trim() === '') {
        throw new Error('Invalid userId: a non-empty string is required.');
    }

    // Define valid plans and their server-side authoritative prices
    const validPlans = {
        'free': 0,
        'pro': 10,
        'enterprise': 50
    };

    // Define valid state transitions (server-side enforcement)
    const validTransitions = {
        'free': ['pro', 'enterprise'],
        'pro': ['free', 'enterprise'],
        'enterprise': ['free', 'pro']
    };

    // Normalize and validate plan names against server-side known values
    if (typeof currentPlan !== 'string' || typeof newPlan !== 'string') {
        throw new Error('Plan names must be strings.');
    }

    const normalizedCurrentPlan = currentPlan.trim().toLowerCase();
    const normalizedNewPlan = newPlan.trim().toLowerCase();

    // Validate that both plans are recognized server-side plans
    if (!(normalizedCurrentPlan in validPlans)) {
        throw new Error(`Invalid current plan: "${currentPlan}". Valid plans are: ${Object.keys(validPlans).join(', ')}.`);
    }

    if (!(normalizedNewPlan in validPlans)) {
        throw new Error(`Invalid new plan: "${newPlan}". Valid plans are: ${Object.keys(validPlans).join(', ')}.`);
    }

    // Reject no-op transitions
    if (normalizedCurrentPlan === normalizedNewPlan) {
        throw new Error('New plan must be different from the current plan.');
    }

    // Enforce valid state transitions (prevent disallowed plan changes)
    if (!validTransitions[normalizedCurrentPlan].includes(normalizedNewPlan)) {
        throw new Error(`Transition from "${normalizedCurrentPlan}" to "${normalizedNewPlan}" is not allowed.`);
    }

    // Recompute prices from trusted server-side data (never trust client-supplied prices)
    let currentPrice;
    if (normalizedCurrentPlan === 'free') {
        currentPrice = 0;
    } else if (normalizedCurrentPlan === 'pro') {
        currentPrice = 10;
    } else if (normalizedCurrentPlan === 'enterprise') {
        currentPrice = 50;
    }

    let newPrice;
    if (normalizedNewPlan === 'free') {
        newPrice = 0;
    } else if (normalizedNewPlan === 'pro') {
        newPrice = 10;
    } else if (normalizedNewPlan === 'enterprise') {
        newPrice = 50;
    }

    // Calculate the charge difference server-side
    const charge = newPrice - currentPrice;

    return {
        newPlan: normalizedNewPlan,
        charge: charge
    };
}

